# Prompt: Using Python: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

from flask import Flask, request, send_file
import os
import subprocess
import boto3

app = Flask(__name__)
s3 = boto3.client('s3')

@app.route('/screenshot', methods=['POST'])
def screenshot():
    if 'url' not in request.json:
        return "URL is missing", 400

    url = request.json['url']
    thumbnail_filename = f"thumbnail_{os.getpid()}.png"

    try:
        subprocess.check_call(["google-chrome", "--headless", "--disable-gpu", "--no-sandbox", "--single-process", url, "--print-to-pdf=/tmp/{thumbnail_filename}"], shell=True)
        with open("/tmp/{thumbnail_filename}", "rb") as f:
            pdf_data = f.read()
        s3.put_object(Body=pdf_data, Key=thumbnail_filename, Bucket="your-bucket-name")
        os.remove("/tmp/{thumbnail_filename}")
    except Exception as e:
        print(f"Error taking screenshot: {e}")
        return "Error taking screenshot", 500

    return send_file(open("/tmp/{thumbnail_filename}", 'rb'), mimetype='image/png')

if __name__ == "__main__":
    app.run()